import { z } from 'zod';

/**
 * Sandbox 适配层类型定义
 */
interface SandboxInfo {
    instanceId: string;
    sandboxToken: string;
    trafficToken?: string;
    sandboxDomain?: string;
    envdVersion?: string;
    expiresAt: string;
}
interface UpdateResponse {
    instanceId: string;
    expiresAt: string;
    message?: string;
}
type SandboxSite = "china" | "global" | "domestic" | "intl" | "overseas" | "cn";
type SandboxOperation = "init" | "resolve_api_base" | "acquire" | "release" | "update" | "create_client" | "command" | "file" | "browser" | "run_code";
type SandboxErrorCode = "SANDBOX_INVALID_PARAMETER" | "SANDBOX_AUTHORIZATION_EXPIRED" | "SANDBOX_RESOURCE_NOT_FOUND" | "SANDBOX_LIMIT_EXCEEDED" | "SANDBOX_FAILED_OPERATION" | "SANDBOX_INTERNAL_ERROR" | "SANDBOX_NETWORK_ERROR" | "SANDBOX_INSTANCE_UNAVAILABLE" | "SANDBOX_CLIENT_ERROR" | "SANDBOX_UNKNOWN_ERROR";
interface SandboxErrorOptions {
    code?: SandboxErrorCode;
    operation?: SandboxOperation;
    status?: number;
    /** 后端返回的原始错误码（如 "ResourceNotFound" / "FailedOperation.Sandbox"），便于排查 */
    businessCode?: number | string;
    businessMessage?: string;
    requestId?: string;
    details?: Record<string, unknown>;
    cause?: unknown;
}
declare class SandboxNotAvailableError extends Error {
    code: SandboxErrorCode;
    operation?: SandboxOperation;
    status?: number;
    businessCode?: number | string;
    businessMessage?: string;
    requestId?: string;
    details?: Record<string, unknown>;
    cause?: unknown;
    constructor(message: string, options?: SandboxErrorOptions);
    /**
     * 在原始报错文本后拼接结构化诊断字段，使 message 自包含。
     *
     * 这样即使调用方用 `String(error)`、打印 `error.message` 或在旧环境里以
     * 有损方式序列化，也能看到 code/operation/status/businessCode/requestId 等关键信息。
     */
    private static composeMessage;
    /**
     * 序列化为包含全部诊断字段的纯对象。
     *
     * `JSON.stringify(error)` 会自动调用此方法，从而避免默认序列化丢失
     * 不可枚举的 message 以及结构化字段的问题。
     */
    toJSON(): Record<string, unknown>;
}
interface SandboxAdapterConfig {
    apiBase?: string;
    authToken: string;
    conversationId: string;
    /** 用户站点，决定 sandbox 控制面 API 域名；Region 只决定实例创建地域 */
    site?: SandboxSite;
    /** API 环境；显式传入时优先于 token 类型和 API_ENV 环境变量 */
    apiEnv?: string;
    projectId?: string;
    deploymentId?: string;
    region?: "ap-beijing" | "ap-singapore";
    /** 沙箱实例初始超时时间，单位秒 */
    timeout?: number;
    sandboxDomain?: string;
    envdVersion?: string;
}
interface CommandRunOpts {
    cwd?: string;
    env?: Record<string, string>;
    user?: "user" | "root";
    timeout?: number;
    onStdout?: (data: string) => void;
    onStderr?: (data: string) => void;
}
interface CommandResult {
    stdout: string;
    stderr: string;
    exitCode: number;
}
interface EntryInfo {
    name: string;
    type: "file" | "dir";
    path: string;
}
interface RunCodeOpts {
    language?: "python" | "javascript" | "r" | "bash";
    onStdout?: (data: string) => void;
    onStderr?: (data: string) => void;
    timeout?: number;
}
interface Execution {
    results: any[];
    logs: {
        stdout: string[];
        stderr: string[];
    };
    error?: {
        name: string;
        message: string;
        traceback: string;
    };
}
interface SandboxDataClient {
    readonly commands: {
        run(command: string, opts?: CommandRunOpts): Promise<CommandResult>;
    };
    readonly files: {
        read(path: string): Promise<string>;
        write(path: string, content: string): Promise<void>;
        list(path: string): Promise<EntryInfo[]>;
        makeDir(path: string): Promise<void>;
        exists(path: string): Promise<boolean>;
        remove(path: string): Promise<void>;
    };
    readonly browser: {
        /** CDP 连接地址 */
        readonly cdpUrl: string;
        /** NoVNC 可视化地址 */
        readonly liveUrl: string;
        /** 导航到 URL */
        goto(url: string, opts?: {
            waitUntil?: string;
        }): Promise<BrowserResult>;
        /** 截取页面截图（base64 PNG） */
        screenshot(opts?: {
            fullPage?: boolean;
        }): Promise<{
            base64Image: string;
        }>;
        /** 点击元素 */
        click(selector: string): Promise<BrowserResult>;
        /** 在输入框键入文本 */
        type(selector: string, text: string): Promise<BrowserResult>;
        /** 执行 JavaScript */
        evaluate(script: string): Promise<BrowserResult>;
        /** 获取页面 HTML 内容 */
        getContent(): Promise<BrowserResult>;
        /** 关闭浏览器连接 */
        close(): Promise<void>;
    };
    runCode(code: string, opts?: RunCodeOpts): Promise<Execution>;
    getHost(port: number): string;
    readonly envdAccessToken: string;
    kill(): Promise<void>;
}
interface BrowserResult {
    success: boolean;
    data?: any;
    error?: string;
}
interface SandboxClient extends SandboxDataClient {
    /** 获取当前已创建沙箱的本地缓存信息；未初始化时抛错，不发网络请求 */
    getInfo(): SandboxInfo;
    /** 主动延长当前沙箱实例寿命，seconds 为数字秒 */
    extendTimeout(seconds: number): Promise<UpdateResponse>;
}

type LangChainToolFactory = (handler: (args: Record<string, any>) => Promise<string>, config: {
    name: string;
    description: string;
    schema: z.ZodTypeAny;
}) => FrameworkTool;
type CrewAIToolFactory = (new (config: {
    name: string;
    description: string;
    args_schema: z.ZodTypeAny;
}) => FrameworkTool) | ((config: {
    name: string;
    description: string;
    args_schema: z.ZodTypeAny;
    coroutine: (args: Record<string, any>) => Promise<string>;
    handler: (args: Record<string, any>) => Promise<any>;
}) => FrameworkTool);

/**
 * 工具错误归一化
 *
 * 业界主流 Agent 框架（OpenAI Agents SDK、Anthropic/MCP、LangChain 系）的共识是：
 * 工具执行失败时应把错误作为结构化结果返回给模型让其自我修复，而不是抛异常中断
 * agent 执行循环。本模块定义统一的结构化错误形态，供各 framework adapter 复用。
 */
/** 结构化工具错误结果。`isError: true` 让上层/模型能明确区分失败与成功返回。 */
interface ToolErrorResult {
    isError: true;
    error: {
        tool: string;
        type: string;
        message: string;
    };
}
/** 判断一个工具执行结果是否为归一化后的结构化错误。 */
declare function isToolErrorResult(value: unknown): value is ToolErrorResult;
/** 把任意抛出的错误归一化为结构化工具错误结果。 */
declare function toToolErrorResult(toolName: string, error: unknown): ToolErrorResult;

/**
 * Tools 类型定义
 */

interface ToolMetadata {
    name: string;
    description: string;
    inputSchema: Record<string, any>;
    execute: (args: Record<string, any>, sandbox: SandboxClient) => Promise<any>;
}
type FrameworkTool = Record<string, any>;

type ClaudeMcpToolResult = {
    content: Array<{
        type: 'text';
        text: string;
    }>;
    isError?: boolean;
};
interface ClaudeMcpToolDefinition {
    name: string;
    description: string;
    inputSchema: Record<string, any>;
    handler(args: Record<string, any>, extra?: unknown): Promise<ClaudeMcpToolResult>;
    _meta?: Record<string, unknown>;
}
interface ClaudeMcpServerOptions {
    alwaysLoad?: boolean;
}
interface ClaudeMcpServerBundle {
    name: string;
    tools: ClaudeMcpToolDefinition[];
    allowedTools: string[];
}
interface ToolsContext {
    readonly commands: FrameworkTool;
    readonly files_read: FrameworkTool;
    readonly files_write: FrameworkTool;
    readonly files_list: FrameworkTool;
    readonly files_exists: FrameworkTool;
    readonly files_remove: FrameworkTool;
    readonly files_make_dir: FrameworkTool;
    readonly browser_fetch: FrameworkTool;
    readonly browser_screenshot: FrameworkTool;
    readonly browser_click: FrameworkTool;
    readonly browser_type: FrameworkTool;
    readonly browser_evaluate: FrameworkTool;
    readonly code_interpreter: FrameworkTool;
    readonly web_search: FrameworkTool;
    all(): FrameworkTool[];
    get(name: ToolName | (string & {})): FrameworkTool | undefined;
    files(): FrameworkTool[];
    browser(): FrameworkTool[];
    toLangChainTools(toolFactory: LangChainToolFactory, names?: ToolName | readonly (ToolName | (string & {}))[]): FrameworkTool[];
    toCrewAITools(baseTool: CrewAIToolFactory, names?: ToolName | readonly (ToolName | (string & {}))[]): FrameworkTool[];
    toClaudeMcpServer(name?: string, options?: ClaudeMcpServerOptions): ClaudeMcpServerBundle;
}
interface BuildToolsOptions {
    debug?: boolean;
}
type FrameworkType = 'claude-agent-sdk' | 'openai-sdk' | 'openai-agents-sdk' | 'langgraph' | 'crewai' | 'deepagents' | 'basic';
type ToolName = 'commands' | 'files_read' | 'files_write' | 'files_list' | 'files_exists' | 'files_remove' | 'files_make_dir' | 'browser_fetch' | 'browser_screenshot' | 'browser_click' | 'browser_type' | 'browser_evaluate' | 'code_interpreter' | 'web_search';

/**
 * Tools 统一入口
 * buildTools(framework, sandbox) → ToolsContext
 */

declare function buildTools(framework: FrameworkType | (string & {}), sandbox: SandboxClient, options?: BuildToolsOptions): ToolsContext;

export { type BuildToolsOptions as B, type ClaudeMcpServerBundle as C, type FrameworkTool as F, type LangChainToolFactory as L, type SandboxAdapterConfig as S, type ToolErrorResult as T, type UpdateResponse as U, type SandboxClient as a, type ClaudeMcpServerOptions as b, type ClaudeMcpToolDefinition as c, type ClaudeMcpToolResult as d, type FrameworkType as e, type SandboxDataClient as f, type SandboxErrorCode as g, type SandboxErrorOptions as h, type SandboxInfo as i, SandboxNotAvailableError as j, type SandboxOperation as k, type ToolMetadata as l, type ToolName as m, type ToolsContext as n, buildTools as o, isToolErrorResult as p, type CrewAIToolFactory as q, toToolErrorResult as t };
